class BankAccount {
    private double balance;  // Hidden! Only this class can touch it

    // Getter = asking "what's my balance?"
    public double getBalance() {
        return balance;
    }

    // Setter with validation = "I want to set my balance"
    public void setBalance(double amount) {
        if (amount >= 0) {  // Validation! Can't have negative balance
